  1→import { existsSync, mkdirSync, readFileSync, writeFileSync } from "node:fs";
  2→import { join } from "node:path";
  3→import { createHash } from "node:crypto";
  4→import { evalite, createScorer } from "evalite";
  5→import { Factuality } from "autoevals";
  6→import { afterAll, beforeAll } from "vitest";
  7→import { RecordId } from "surrealdb";
  8→import { entityPrecisionScorer } from "./scorers/entity-precision";
  9→import { entityRecallScorer } from "./scorers/entity-recall";
 10→import { noPhantomPersonsScorer } from "./scorers/no-phantom-persons";
 11→import { evidenceGroundedScorer } from "./scorers/evidence-grounded";
 12→import { noExtraEntitiesScorer } from "./scorers/no-extra-entities";
 13→import { noContextBleedScorer } from "./scorers/no-context-bleed";
 14→import { evidenceSourceCurrentMessageScorer } from "./scorers/evidence-source-current-message";
 15→import { resolvedFromLineageScorer } from "./scorers/resolved-from-lineage";
 16→import { toolFilteringScorer } from "./scorers/tool-filtering";
 17→import { forbiddenKindsScorer } from "./scorers/forbidden-kinds";
 18→import { relationRecallScorer } from "./scorers/relation-recall";
 19→import { categoryAccuracyScorer } from "./scorers/category-accuracy";
 20→import type { ExtractionEvalOutput, GoldenCase, GoldenCaseIntent } from "./types";
 21→import { normalizeForSubstring } from "./scorers/shared";
 22→import { extractStructuredGraph } from "../app/src/server/extraction/extract-graph";
 23→import { persistExtractionOutput, appendExtractedTools } from "../app/src/server/extraction/persist-extraction";
 24→import { loadExtractionConversationContext, loadConversationGraphContext } from "../app/src/server/extraction/context-loaders";
 25→import type { SourceRecord } from "../app/src/server/extraction/types";
 26→import { loadWorkspaceProjects } from "../app/src/server/workspace/workspace-scope";
 27→import {
 28→  type EvalRuntime,
 29→  setupEvalRuntime,
 30→  teardownEvalRuntime,
 31→  seedWorkspace,
 32→  seedConversationContext,
 33→  seedUserMessage,
 34→  seedGraphEntities,
 35→  loadWorkspacePeopleCount,
 36→  createDeterministicIdGenerator,
 37→} from "./eval-test-kit";
 38→
 39→const extractionModel = requireEnv("EXTRACTION_MODEL");
 40→const autoevalModel = requireEnv("AUTOEVAL_MODEL");
 41→
 42→const cacheDir = process.env.EVAL_CACHE_DIR ?? "eval-results/cache";
 43→const cachePath = join(cacheDir, "extraction-cache.json");
 44→const resultCache = loadCache(cachePath);
 45→const cases = JSON.parse(readFileSync(join(process.cwd(), "evals", "data", "golden-cases.json"), "utf8")) as GoldenCase[];
 46→assertAutoevalEnv();
 47→
 48→// strict_single is reserved for unambiguous one-entity probes.
 49→// Cases where multiple extractions are semantically valid should use multi_allowed.
 50→const intentScoreWeights: Record<
 51→  GoldenCaseIntent,
 52→  Record<
 53→    | "entity-precision"
 54→    | "entity-recall"
 55→    | "no-extra-entities"
 56→    | "no-phantom-persons"
 57→    | "evidence-grounded"
 58→    | "no-context-bleed"
 59→    | "evidence-source-current-message"
 60→    | "resolved-from-lineage"
 61→    | "tool-filtering"
 62→    | "forbidden-kinds"
 63→    | "factuality"
 64→    | "relation-recall"
 65→    | "category-accuracy",
 66→    number
 67→  >
 68→> = {
 69→  strict_single: {
 70→    "entity-precision": 0.16,
 71→    "entity-recall": 0.16,
 72→    "no-extra-entities": 0.18,
 73→    "no-phantom-persons": 0.12,
 74→    "evidence-grounded": 0.08,
 75→    "no-context-bleed": 0.05,
 76→    "evidence-source-current-message": 0.05,
 77→    "resolved-from-lineage": 0.04,
 78→    "tool-filtering": 0.06,
 79→    "forbidden-kinds": 0.08,
 80→    factuality: 0.02,
 81→    "relation-recall": 0,
 82→    "category-accuracy": 0.1,
 83→  },
 84→  multi_allowed: {
 85→    "entity-precision": 0.21,
 86→    "entity-recall": 0.21,
 87→    "no-extra-entities": 0.05,
 88→    "no-phantom-persons": 0.11,
 89→    "evidence-grounded": 0.08,
 90→    "no-context-bleed": 0.04,
 91→    "evidence-source-current-message": 0.06,
 92→    "resolved-from-lineage": 0.04,
 93→    "tool-filtering": 0.04,
 94→    "forbidden-kinds": 0.06,
 95→    factuality: 0.02,
 96→    "relation-recall": 0.03,
 97→    "category-accuracy": 0.1,
 98→  },
 99→};
100→
101→let runtime: EvalRuntime;
102→
103→beforeAll(async () => {
104→  runtime = await setupEvalRuntime("extraction");
105→}, 120_000);
106→
107→afterAll(async () => {
108→  await teardownEvalRuntime(runtime);
109→}, 120_000);
110→
111→const factualityScorer = createScorer<GoldenCase, ExtractionEvalOutput, GoldenCase>({
112→  name: "factuality",
113→  description: "Average factual grounding score for extracted entity texts against matched provenance evidence snippets.",
114→  scorer: async ({ input, output }) => {
115→    if (output.extractedEntities.length === 0) {
116→      return { score: 1 };
117→    }
118→
119→    let total = 0;
120→    for (const entity of output.extractedEntities) {
121→      const snippet = resolveEntityEvidenceSnippet(entity.text, output.evidenceRows, input.input);
122→      const result = await Factuality({
123→        input: snippet,
124→        output: entity.text,
125→        expected: snippet,
126→        model: autoevalModel,
127→      });
128→      total += result.score ?? 0;
129→    }
130→
131→    return { score: total / output.extractedEntities.length };
132→  },
133→});
134→
135→evalite<GoldenCase, ExtractionEvalOutput, GoldenCase>("Extraction Golden Cases", {
136→  data: cases.map((testCase) => ({ input: testCase, expected: testCase })),
137→  task: async (input) => runCase(input),
138→  scorers: [
139→    entityPrecisionScorer,
140→    entityRecallScorer,
141→    noExtraEntitiesScorer,
142→    noPhantomPersonsScorer,
143→    evidenceGroundedScorer,
144→    noContextBleedScorer,
145→    evidenceSourceCurrentMessageScorer,
146→    resolvedFromLineageScorer,
147→    toolFilteringScorer,
148→    forbiddenKindsScorer,
149→    relationRecallScorer,
150→    categoryAccuracyScorer,
151→    factualityScorer,
152→  ],
153→  columns: ({ input, output, scores }) => [
154→    { label: "Case", value: input.id },
155→    { label: "Intent", value: input.intent },
156→    { label: "Ent", value: `${output.extractedEntities.length}/${input.expectedEntities.length}` },
157→    { label: "Prec", value: formatScoreCell(scoreByName(scores, "entity-precision")) },
158→    { label: "Rec", value: formatScoreCell(scoreByName(scores, "entity-recall")) },
159→    { label: "Cat", value: formatScoreCell(scoreByName(scores, "category-accuracy")) },
160→    {
161→      label: "Avg",
162→      value: computeWeightedAverage(input.intent, scores).toFixed(2),
163→    },
164→  ],
165→});
166→
167→function scoreByName(
168→  scores: Array<{ name: string; score: number | null }>,
169→  name: string,
170→): number {
171→  const match = scores.find((score) => score.name === name);
172→  if (!match || match.score === null || Number.isNaN(match.score)) {
173→    throw new Error(`Missing score for scorer: ${name}`);
174→  }
175→
176→  return match.score;
177→}
178→
179→function formatScoreCell(value: number): string {
180→  return value.toFixed(2);
181→}
182→
183→function computeWeightedAverage(
184→  intent: GoldenCaseIntent,
185→  scores: Array<{ name: string; score: number | null }>,
186→): number {
187→  const weights = intentScoreWeights[intent];
188→  if (!weights) {
189→    throw new Error(`Unknown golden case intent: ${intent}`);
190→  }
191→
192→  let weightedTotal = 0;
193→  let weightTotal = 0;
194→  for (const [scorerName, weight] of Object.entries(weights)) {
195→    if (weight <= 0) {
196→      continue;
197→    }
198→
199→    weightedTotal += scoreByName(scores, scorerName) * weight;
200→    weightTotal += weight;
201→  }
202→
203→  if (weightTotal === 0) {
204→    throw new Error(`No scorer weights configured for intent: ${intent}`);
205→  }
206→
207→  return weightedTotal / weightTotal;
208→}
209→
210→function resolveEntityEvidenceSnippet(
211→  entityText: string,
212→  evidenceRows: Array<{ evidence?: string; fromText?: string; model?: string }>,
213→  fallbackInput: string,
214→): string {
215→  const normalizedEntityText = normalizeForSubstring(entityText);
216→  const matched = evidenceRows.find((row) => normalizeForSubstring(row.fromText ?? "") === normalizedEntityText);
217→  const snippet = matched?.evidence ?? evidenceRows[0]?.evidence ?? fallbackInput;
218→  return snippet.trim().length > 0 ? snippet : fallbackInput;
219→}
220→
221→async function runCase(testCase: GoldenCase): Promise<ExtractionEvalOutput> {
222→  const cacheKey = buildCaseCacheKey(extractionModel, testCase);
223→  const cached = resultCache[cacheKey];
224→  if (cached) {
225→    return {
226→      ...cached,
227→      extractedTools: cached.extractedTools ?? [],
228→      extractedRelations: cached.extractedRelations ?? [],
229→    };
230→  }
231→
232→  const nextId = createDeterministicIdGenerator(testCase.id);
233→  const { workspaceRecord, workspaceName, projectRecord, conversationRecord, ownerPersonCount } = await seedWorkspace(runtime.surreal, testCase.workspace_name, nextId);
234→  const conversationId = conversationRecord.id as string;
235→  const seededContext = testCase.context ?? [];
236→  const contextMessageIds = seededContext.length > 0
237→    ? await seedConversationContext(runtime.surreal, conversationRecord, seededContext, nextId)
238→    : [];
239→
240→  if (testCase.workspace_seed && testCase.workspace_seed.length > 0) {
241→    await seedGraphEntities(runtime.surreal, workspaceRecord, projectRecord, conversationRecord, testCase.workspace_seed, nextId);
242→  }
243→
244→  const userMessageRecord = await seedUserMessage(runtime.surreal, conversationRecord, testCase.input, nextId);
245→
246→  const extractionConversationContext = await loadExtractionConversationContext({
247→    surreal: runtime.surreal,
248→    conversationId,
249→    currentMessageRecord: userMessageRecord,
250→  });
251→  const extractionGraphContext = await loadConversationGraphContext(runtime.surreal, conversationId, 60);
252→  const workspaceProjects = await loadWorkspaceProjects(runtime.surreal, workspaceRecord);
253→  const workspaceProjectNames = workspaceProjects.map((project) => project.name);
254→
255→  const extraction = await extractStructuredGraph({
256→    extractionModel: runtime.extractionModel,
257→    conversationHistory: extractionConversationContext.conversationHistory,
258→    currentMessage: extractionConversationContext.currentMessage,
259→    graphContext: extractionGraphContext,
260→    sourceText: testCase.input,
261→    onboarding: true,
262→    workspaceName,
263→    projectNames: workspaceProjectNames,
264→  });
265→
266→  const now = new Date();
267→  const persistence = await persistExtractionOutput({
268→    surreal: runtime.surreal,
269→    embeddingModel: runtime.embeddingModel,
270→    embeddingDimension: runtime.config.embeddingDimension,
271→    extractionModelId: runtime.config.extractionModelId,
272→    extractionStoreThreshold: runtime.config.extractionStoreThreshold,
273→    workspaceRecord,
274→    sourceRecord: userMessageRecord as SourceRecord,
275→    sourceKind: "message",
276→    sourceLabel: testCase.input.slice(0, 140),
277→    promptText: testCase.input,
278→    output: extraction,
279→    sourceMessageRecord: userMessageRecord,
280→    extractionHistoryMessageIds: extractionConversationContext.conversationHistory.map(
281→      (row) => row.id.id as string,
282→    ),
283→    now,
284→  });
285→
286→  await appendExtractedTools(runtime.surreal, workspaceRecord, persistence.tools, now);
287→
288→  const [evidenceRows] = await runtime.surreal
289→    .query<[Array<{
290→      evidence?: string;
291→      from_text?: string;
292→      model?: string;
293→      evidence_source?: RecordId<"message", string>;
294→      resolved_from?: RecordId<"message", string>;
295→    }>]>(
296→      "SELECT evidence, from_text, model, evidence_source, resolved_from FROM extraction_relation WHERE `in` = $source;",
297→      { source: userMessageRecord },
298→    )
299→    .collect<[Array<{
300→      evidence?: string;
301→      from_text?: string;
302→      model?: string;
303→      evidence_source?: RecordId<"message", string>;
304→      resolved_from?: RecordId<"message", string>;
305→    }>]>();
306→
307→  const personCount = await loadWorkspacePeopleCount(runtime.surreal, workspaceRecord);
308→  const [workspaceToolRows] = await runtime.surreal
309→    .query<[Array<{ tools?: string[] }>]>("SELECT tools FROM $workspace LIMIT 1;", {
310→      workspace: workspaceRecord,
311→    })
312→    .collect<[Array<{ tools?: string[] }>]>();
313→  const extractedTools = workspaceToolRows[0]?.tools ?? [];
314→
315→  const [relationRows] = await runtime.surreal
316→    .query<[Array<{
317→      kind: string;
318→      in: { tb: string };
319→      out: { tb: string };
320→      from_text: string;
321→      to_text: string;
322→      confidence: number;
323→    }>]>(
324→      "SELECT kind, `in`, out, from_text, to_text, confidence FROM entity_relation WHERE source_message = $source AND kind != 'POSSIBLE_DUPLICATE';",
325→      { source: userMessageRecord },
326→    )
327→    .collect<[Array<{
328→      kind: string;
329→      in: { tb: string };
330→      out: { tb: string };
331→      from_text: string;
332→      to_text: string;
333→      confidence: number;
334→    }>]>();
335→
336→  const output: ExtractionEvalOutput = {
337→    caseId: testCase.id,
338→    input: testCase.input,
339→    userMessageId: userMessageRecord.id as string,
340→    contextMessageIds,
341→    extractedEntities: persistence.entities.map((e) => ({
342→      kind: e.kind,
343→      text: e.text,
344→      confidence: e.confidence,
345→      ...(e.category ? { category: e.category } : {}),
346→    })),
347→    extractedTools,
348→    personCount,
349→    ownerPersonCount,
350→    evidenceRows: evidenceRows.map((row) => ({
351→      evidence: row.evidence,
352→      fromText: row.from_text,
353→      model: row.model,
354→      evidenceSourceId: row.evidence_source?.id as string | undefined,
355→      resolvedFromId: row.resolved_from?.id as string | undefined,
356→    })),
357→    extractedRelations: relationRows.map((row) => ({
358→      kind: row.kind,
359→      fromKind: row.in.tb,
360→      fromText: row.from_text,
361→      toKind: row.out.tb,
362→      toText: row.to_text,
363→      confidence: row.confidence,
364→    })),
365→  };
366→
367→  resultCache[cacheKey] = output;
368→  saveCache(cachePath, resultCache);
369→  return output;
370→}
371→
372→function loadCache(path: string): Record<string, ExtractionEvalOutput> {
373→  if (!existsSync(path)) {
374→    return {};
375→  }
376→
377→  return JSON.parse(readFileSync(path, "utf8")) as Record<string, ExtractionEvalOutput>;
378→}
379→
380→function saveCache(path: string, cache: Record<string, ExtractionEvalOutput>): void {
381→  mkdirSync(cacheDir, { recursive: true });
382→  writeFileSync(path, JSON.stringify(cache, null, 2));
383→}
384→
385→function assertAutoevalEnv(): void {
386→  const hasOpenAiKey = hasEnv("OPENAI_API_KEY");
387→  const hasBraintrustKey = hasEnv("BRAINTRUST_API_KEY");
388→  if (!hasOpenAiKey && !hasBraintrustKey) {
389→    throw new Error(
390→      "Missing evaluator credentials. Set OPENAI_API_KEY (recommended for OPENAI_BASE_URL/OpenRouter) or BRAINTRUST_API_KEY.",
391→    );
392→  }
393→
394→  if (!hasEnv("OPENAI_BASE_URL")) {
395→    throw new Error("Missing OPENAI_BASE_URL for autoevals provider routing.");
396→  }
397→}
398→
399→function requireEnv(name: string): string {
400→  const value = process.env[name];
401→  if (!value || value.trim().length === 0) {
402→    throw new Error(`Missing required environment variable: ${name}`);
403→  }
404→  return value;
405→}
406→
407→function hasEnv(name: string): boolean {
408→  const value = process.env[name];
409→  return value !== undefined && value.trim().length > 0;
410→}
411→
412→function buildCaseCacheKey(modelId: string, testCase: GoldenCase): string {
413→  const cacheVersion = "classification-v16";
414→  const caseHash = createHash("sha256").update(JSON.stringify(testCase)).digest("hex").slice(0, 24);
415→  return `${cacheVersion}:${modelId}:${testCase.id}:${caseHash}`;
416→}
417→

